joi_block.script:
t1 = (#LightSensor #LivingRoom).lightSensor_brightness
delay(1 HOUR)
t2 = (#LightSensor #LivingRoom).lightSensor_brightness
diff = t1 - t2
if (diff < 0) {
diff = t2 - t1
}
if (diff >= 200) {
(#Plug #Switch #LivingRoom #MoodLight).switch_on()
}

